population.algorithm:
Greedy insertion with cost-aware fallback: attempt to insert each ship into existing routes in ascending current-cost order, if all fail create a new route at first unused assign slot.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type idxCost struct {
		idx  int
		cost float64
	}
	existing := make([]idxCost, 0, MAXASSIGNS)
	for i := 0; i < dispatch.AssignsLen; i++ {
		if dispatch.Assigns[i].StationsLen > 0 {
			existing = append(existing, idxCost{i, dispatch.Assigns[i].Cost})
		}
	}
	sort.SliceStable(existing, func(a, b int) bool {
		return existing[a].cost < existing[b].cost
	})
	orderIndices := make([]int, len(oris))
	for i := range oris {
		orderIndices[i] = i
	}
	rand.Shuffle(len(orderIndices), func(i, j int) {
		orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
	})
	insertedIdx := 0
	for _, oi := range orderIndices {
		id := total_ship + oi
		inserted := false
		for _, ic := range existing {
			if dispatch.Assigns[ic.idx].AddShip(id, oris[oi], dess[oi]) {
				dispatch.Assigns[ic.idx].GenRoute()
				if dispatch.Assigns[ic.idx].Cost >= 0 {
					inserted = true
					break
				}
				dispatch.Assigns[ic.idx].RemoveShip(id)
				dispatch.Assigns[ic.idx].GenRoute()
			}
		}
		if !inserted {
			fallbackFound := false
			for i := 0; i < MAXASSIGNS; i++ {
				if dispatch.Assigns[i].StationsLen == 0 {
					ok := dispatch.Assigns[i].AddShip(id, oris[oi], dess[oi])
					if ok {
						dispatch.Assigns[i].GenRoute()
						if dispatch.Assigns[i].Cost >= 0 {
							if i >= dispatch.AssignsLen {
								dispatch.AssignsLen = i + 1
							}
							existing = append(existing, idxCost{i, dispatch.Assigns[i].Cost})
							sort.SliceStable(existing, func(a, b int) bool {
								return existing[a].cost < existing[b].cost
							})
							fallbackFound = true
							break
						}
						dispatch.Assigns[i].RemoveShip(id)
						dispatch.Assigns[i].GenRoute()
					}
				}
			}
			if !fallbackFound {
				continue
			}
		}
		insertedIdx++
	}
	dispatch.RenewnTotalCost()
	return dispatch

