Greedy insertion with fallback: attempt all feasible assign permutations per order sorted by marginal cost increase, then try empty assigns, finally create new assign if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx       int
		deltaCost float64
		ok        bool
	}
	orderCount := len(oris)
	for jj := 0; jj < orderCount; jj++ {
		bestCand := cand{-1, 0, false}
		candidates := make([]cand, 0, dispatch.AssignsLen+1)

		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			prevCost := dispatch.Assigns[ii].Cost
			added := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
			if added {
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					delta := dispatch.Assigns[ii].Cost - prevCost
					candidates = append(candidates, cand{ii, delta, true})
				}
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
		}

		sort.Slice(candidates, func(a, b int) bool {
			if candidates[a].ok != candidates[b].ok {
				return candidates[a].ok
			}
			return candidates[a].deltaCost < candidates[b].deltaCost
		})

		if len(candidates) > 0 && candidates[0].ok {
			bestCand = candidates[0]
		}

		inserted := false
		if bestCand.ok {
			success := dispatch.Assigns[bestCand.idx].AddShip(total_ship+jj, oris[jj], dess[jj])
			if success {
				dispatch.Assigns[bestCand.idx].GenRoute()
				if dispatch.Assigns[bestCand.idx].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[bestCand.idx].RemoveShip(total_ship + jj)
					dispatch.Assigns[bestCand.idx].GenRoute()
				}
			}
		}

		if !inserted {
			foundEmpty := false
			for ii := 0; ii < dispatch.AssignsLen; ii++ {
				if dispatch.Assigns[ii].StationsLen == 0 {
					added := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
					if added {
						dispatch.Assigns[ii].GenRoute()
						if dispatch.Assigns[ii].Cost >= 0 {
							inserted = true
							foundEmpty = true
							break
						} else {
							dispatch.Assigns[ii].RemoveShip(total_ship + jj)
							dispatch.Assigns[ii].GenRoute()
						}
					}
				}
			}
			if !foundEmpty && dispatch.AssignsLen < MAXASSIGNS {
				newIdx := dispatch.AssignsLen
				added := dispatch.Assigns[newIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
				if added {
					dispatch.Assigns[newIdx].GenRoute()
					if dispatch.Assigns[newIdx].Cost >= 0 {
						dispatch.AssignsLen++
						inserted = true
					} else {
						dispatch.Assigns[newIdx].RemoveShip(total_ship + jj)
						dispatch.Assigns[newIdx].GenRoute()
					}
				}
			}
		}

		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			newIdx := dispatch.AssignsLen
			added := dispatch.Assigns[newIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			if added {
				dispatch.Assigns[newIdx].GenRoute()
				if dispatch.Assigns[newIdx].Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					dispatch.Assigns[newIdx].RemoveShip(total_ship + jj)
					dispatch.Assigns[newIdx].GenRoute()
				}
			}
		}
	}
