Greedy insertion with route regeneration fallback: attempt all existing non-empty routes first, then try empty/seed routes, always ensuring each order is placed somewhere via a guaranteed seed assign if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx   int
		delta float64
		ok    bool
	}
	randOrder := make([]int, len(oris))
	for i := range randOrder {
		randOrder[i] = i
	}
	rand.Shuffle(len(randOrder), func(i, j int) {
		randOrder[i], randOrderOrder[j] = randOrder[j], randOrder[i]
	})
	shuffledOris := make([]Station, len(oris))
	shuffledDess := make([]Station, len(dess))
	for i, idx := range randOrder {
		shuffledOris[i] = oris[idx]
		shuffledDess[i] = dess[idx]
		realIdx := total_ship + idx
		bestCand := candidate{-1, 0, false}
		inserted := false
		for k := 0; k < dispatch.AssignsLen; k++ {
			prevCost := dispatch.Assigns[k].Cost
			ok := dispatch.Assigns[k].AddShip(realIdx, shuffledOris[i], shuffledDess[i])
			if ok {
				dispatch.Assigns[k].GenRoute()
				if dispatch.Assigns[k].Cost >= 0 {
					delta := dispatch.Assigns[k].Cost - prevCost
					if !bestCand.ok || delta < bestCand.delta {
						bestCand.idx = k
						bestCand.delta = delta
						bestCand.ok = true
					}
				}
				dispatch.Assigns[k].RemoveShip(realIdx)
				dispatch.Assigns[k].GenRoute()
			}
		}
		if bestCand.ok {
			dispatch.Assigns[bestCand.idx].AddShip(realIdx, shuffledOris[i], shuffledDess[i])
			dispatch.Assigns[bestCand.idx].GenRoute()
			inserted = true
		} else {
			for k := dispatch.AssignsLen; k < MAXASSIGNS; k++ {
				ok := dispatch.Assigns[k].AddShip(realIdx, shuffledOris[i], shuffledDess[i])
				if ok {
					dispatch.Assigns[k].GenRoute()
					if dispatch.Assigns[k].Cost >= 0 {
						if k >= dispatch.AssignsLen {
							dispatch.AssignsLen = k + 1
						}
						inserted = true
						break
					} else {
						dispatch.Assigns[k].RemoveShip(realIdx)
						dispatch.Assigns[k].GenRoute()
					}
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				k := dispatch.AssignsLen
				ok := dispatch.Assigns[k].AddShip(realIdx, shuffledOris[i], shuffledDess[i])
				if ok {
					dispatch.Assigns[k].GenRoute()
					if dispatch.Assigns[k].Cost >= 0 {
						dispatch.AssignsLen++
						inserted = true
					} else {
						dispatch.Assigns[k].RemoveShip(realIdx)
						dispatch.Assigns[k].GenRoute()
					}
				}
			}
			if !inserted {
				seedIdx := dispatch.AssignsLen
				if seedIdx < MAXASSIGNS {
					dispatch.Assigns[seedIdx].AddShip(realIdx, shuffledOris[i], shuffledDess[i])
					dispatch.Assigns[seedIdx].GenRoute()
					dispatch.AssignsLen++
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

