func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx       int
		delta     float64
		score     float64
		stationCnt int
	}
	const INF = 1e18
	nAssigns := dispatch.AssignsLen
	if nAssigns == 0 {
		nAssigns = 1
	}
	for oIdx, ori := range oris {
		des := dess[oIdx]
		shipID := total_ship + oIdx
		baseDist := cal_dis(ori, des)
		bestCandidate := candidate{-1, INF, INF, 0}
		emptySlot := -1
		for ai := 0; ai < nAssigns; ai++ {
			a := &dispatch.Assigns[ai]
