		if !inserted {
			fallbackIdx := -1
			for i := 0; i < MAXASSIGNS; i++ {
				if dispatch.Assigns[i].StationsLen == 0 {
					fallbackIdx = i
					break
				}
			}
			if fallbackIdx == -1 && dispatch.AssignsLen < MAXASSIGNS {
				fallbackIdx = dispatch.AssignsLen
			}
			if fallbackIdx != -1 {
				target := &dispatch.Assigns[fallbackIdx]
