Greedy best-fit insertion with fallback empty vehicle creation: evaluate all feasible vehicles per order using marginal cost increase, select minimum cost increase option, otherwise create new vehicle if capacity allows.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	currentAssignsLen := dispatch.AssignsLen
	maxPossibleAssigns := MAXASSIGNS

	for jj := 0; jj < orderCount; jj++ {
		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj

		bestIdx := -1
		bestCostIncrease := 1e100

		for idx := 0; idx < currentAssignsLen; idx++ {
			assign := &dispatch.Assigns[idx]
			oldCost := assign.Cost

			success := assign.AddShip(shipID, ori, des)
			if success {
				assign.GenRoute()
				newCost := assign.Cost
				if newCost >= 0 {
					costIncrease := newCost - oldCost
					if costIncrease < bestCostIncrease {
						bestCostIncrease = costIncrease
						bestIdx = idx
					}
				}
			}
			assign.RemoveShip(shipID)
			assign.GenRoute()
		}

		if bestIdx >= 0 {
			dispatch.Assigns[bestIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestIdx].GenRoute()
		} else {
			fallbackInserted := false
			if currentAssignsLen < maxPossibleAssigns {
				idxNew := currentAssignsLen
				success := dispatch.Assigns[idxNew].AddShip(shipID, ori, des)
				if success {
					dispatch.Assigns[idxNew].GenRoute()
					if dispatch.Assigns[idxNew].Cost >= 0 {
						dispatch.AssignsLen++
						currentAssignsLen++
						fallbackInserted = true
					} else {
						dispatch.Assigns[idxNew].RemoveShip(shipID)
						dispatch.Assigns[idxNew].GenRoute()
					}
				}
			}
			if !fallbackInserted {
				for idx := 0; idx < currentAssignsLen; idx++ {
					success := dispatch.Assigns[idx].AddShip(shipID, ori, des)
					if success {
						dispatch.Assigns[idx].GenRoute()
