population.algorithm:
Greedy insertion with regret heuristic and fallback to best‑feasible assign: for each order, evaluate all assigns’ incremental costs, pick the one minimizing a weighted sum of immediate and future opportunity costs; if none accepts, force‑insert into the currently cheapest assign even if it means removing its most costly ship later, then regenerate routes.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx     int
		delta   float64
		second  float64
		accepts bool
	}
	n := len(oris)
	assignCnt := dispatch.AssignsLen
	if assignCnt == 0 {
		assignCnt = 1
	}
	bestFeasibleDelta := make([]float64, n)
	fallbackIdx := make([]int, n)
	for i := range bestFeasibleDelta {
		bestFeasibleDelta[i] = 1e30
		fallbackIdx[i] = -1
	}
	orderSeq := make([]int, n)
	for i := range orderSeq {
		orderSeq[i] = i
	}
	rand.Shuffle(n, func(a, b int) { orderSeq[a], orderSeq[b] = orderSeq[b], orderSeq[a] })
	for _, jj := range orderSeq {
		bestCand := cand{-1, 1e30, 1e30, false}
		bestRegret := -1e30
		for ii := 0; ii < assignCnt; ii++ {
			oldCost := dispatch.Assigns[ii].Cost
			ok := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					dispatch.Assigns[ii].RemoveShip(total_ship + jj)
					dispatch.Assigns[ii].GenRoute()
					c := cand{ii, delta, 1e30, true}
					regret := -delta
					if regret > bestRegret {
						bestRegret = regret
						bestCand = c
						bestFeasibleDelta[jj] = delta
						fallbackIdx[jj] = ii
					}
				} else {
					dispatch.Assigns[ii].RemoveShip(total_ship + jj)
					dispatch.Assigns[ii].GenRoute()
				}
			}
		}
		if bestCand.accepts {
			dispatch.Assigns[bestCand.idx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestCand.idx].GenRoute()
			if bestCand.idx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
				if dispatch.AssignsLen > MAXASSIGNS {
					dispatch.AssignsLen = MAXASSIGNS
				}
				assignCnt = dispatch.AssignsLen
			}
			continue
		}
		forced := false
		minCurrCost := 1e30
		forcedIdx := -1
		for ii := 0; ii < assignCnt; ii++ {
			currCost := dispatch.Assigns[ii].Cost
			if currCost < minCurrCost {
				minCurrCost = currCost
				forcedIdx = ii
			}
		}
		if forcedIdx >= 0 && forcedIdx < MAXASSIGNS {
			ok := dispatch.Assigns[forcedIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[forcedIdx].GenRoute()
				if dispatch.Assigns[forcedIdx].Cost >= 0 {
					if forcedIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen++
						if dispatch.AssignsLen > MAXASSIGNS {
							dispatch.AssignsLen = MAXASSIGNS
						}
						assignCnt = dispatch.AssignsLen
					}
					forced = true
				} else {
					dispatch.Assigns[forcedIdx].RemoveShip(total_ship + jj)
					dispatch.Assigns[forcedIdx].GenRoute()
				}
			}
		}
		if !forced {
			safeIdx := dispatch.AssignsLen
			if safeIdx < MAXASSIGNS {
				dispatch.Assigns[safeIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
				dispatch.Assigns[safeIdx].GenRoute()
				dispatch.AssignsLen++
				if dispatch.AssignsLen > MAXASSIGNS {
					dispatch.AssignsLen = MAXASSIGNS
				}
				assignCnt = dispatch.AssignsLen
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

