Greedy insertion with regret-based heuristic evaluating multiple candidate positions across all routes, fallback to empty route if necessary.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		assignIdx int
		costDelta float64
		valid     bool
	}
	nOrders := len(oris)
	nRoutes := dispatch.AssignsLen
	for i := nRoutes; i < MAXASSIGNS; i++ {
		dispatch.Assigns[i].Cost = 0
		dispatch.Assigns[i].StationsLen = 0
	}
	orderIndices := make([]int, nOrders)
	for i := range orderIndices {
		orderIndices[i] = i
	}
	rand.Shuffle(nOrders, func(i, j int) {
		orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
	})
	for _, idx := range orderIndices {
		ori := oris[idx]
		des := dess[idx]
		shipID := total_ship + idx
		bestCand := cand{-1, 1e30, false}
		secondBestCand := cand{-1, 1e30, false}
		allEmptyCandidates := make([]int, 0, MAXASSIGNS-nRoutes+1)
		for r := 0; r < MAXASSIGNS; r++ {
			if r >= nRoutes && dispatch.Assigns[r].StationsLen == 0 {
				allEmptyCandidates = append(allEmptyCandidates, r)
				continue
			}
			oldCost := dispatch.Assigns[r].Cost
			addOk := dispatch.Assigns[r].AddShip(shipID, ori, des)
			if !addOk {
				continue
			}
			dispatch.Assigns[r].GenRoute()
			newCost := dispatch.Assigns[r].Cost
			if newCost >= 0 {
				delta := newCost - oldCost
				isValid := true
				c := cand{r, delta, isValid}
				if c.costDelta < bestCand.costDelta {
					secondBestCand = bestCand
					bestCand = c
				} else if c.costDelta < secondBestCand.costDelta {
					secondBestCand = c
				}
			}
			dispatch.Assigns[r].RemoveShip(shipID)
			dispatch.Assigns[r].GenRoute()
		}
		selectedAssign := -1
		if bestCand.valid {
			regretVal := 0.0
			if secondBestCand.valid {
				regretVal = secondBestCand.costDelta - bestCand.costDelta
			} else {
				regretVal = 1e9
			}
			if regretVal > 10000 && len(allEmptyCandidates) > 0 {
				useNew := true
				for _, ec := range allEmptyCandidates {
					if ec < selectedAssign || selectedAssign == -1 {
						selectedAssign = ec
					}
				}
				if useNew {
					selectedAssign = allEmptyCandidates[0]
				}
			} else {
				selectedAssign = bestCand.assignIdx
			}
		}
		fallbackUsed := false
		if selectedAssign == -1 {
			fallbackUsed = true
			for _, ec := range allEmptyCandidates {
				selectedAssign = ec
				break
			}
			if selectedAssign == -1 {
				selectedAssign = nRoutes
			}
		}
		if selectedAssign >= nRoutes && selectedAssign < MAXASSIGNS {
			nRoutes++
		}
		ok := dispatch.Assigns[selectedAssign].AddShip(shipID, ori, des)
		if !ok && fallbackUsed {
			dispatch.Assigns[selectedAssign].Cost = 0
			dispatch.Assigns[selectedAssign].StationsLen = 0
			ok = dispatch.Assigns[selectedAssign].AddShip(shipID, ori, des)
		}
		if ok {
			dispatch.Assigns[selectedAssign].GenRoute()
			if dispatch.Assigns[selectedAssign].Cost < 0 {
				dispatch.Assigns[selectedAssign].RemoveShip(shipID)
				dispatch.Assigns[selectedAssign].GenRoute()
				if selectedAssign >= dispatch.AssignsLen {
					nRoutes--
				}
			}
		}
		dispatch.AssignsLen = nRoutes
	}
	dispatch.RenewnTotalCost()
	return dispatch

